texttool_globals_toast___child_lock_active = TextObject(bs_BA="MMI displej suvozača je trenutno blokiran.", cs_CZ="Displej MMI pro spolujezdce je v současné době uzamčen.", da_DK="MMI-displayet til forsædepassageren er p.t. spærret.", de_DE="Das MMI Beifahrerdisplay ist zurzeit gesperrt.", el_GR="Η οθόνη ΜΜΙ του συνοδηγού προς το παρόν είναι φραγμένη.", en_GB="The MMI front passenger display is currently locked.", es_ES="La pantalla del MMI del acompañante está bloqueada\nactualmente.", fi_FI="Etumatkustajan MMI-näyttö on tällä hetkellä lukittu.", fr_FR="L'écran MMI du passager avant est verrouillé actuellement.", hr_HR="Suvozačev zaslon MMI-ja trenutačno je blokiran.", hu_HU="Az MMI-utaskijelző jelenleg le van tiltva.", it_IT="L'MMI del display del passeggero anteriore è bloccato\nal momento.", nl_NL="Het MMI-bijrijdersdisplay is momenteel geblokkeerd.", no_NO="MMI-passasjerdisplayet er sperret for øyeblikket.", pl_PL="Wyświetlacz MMI pasażera jest obecnie zablokowany.", pt_PT="De momento o ecrã MMI do passageiro está desativado.", ro_RO="Afişajul MMI al pasagerului faţă este momentan blocat.", ru_RU="Дисплей MMI переднего пассажира в настоящее время\nзаблокирован.", sk_SK="Displej spolujazdca systému MMI je momentálne zablokovaný.", sl_SI="Sovoznikov zaslon sistema MMI je trenutno blokiran.", sr_RS="MMI displej suvozača je trenutno blokiran.", sv_SE="MMI-passagerardisplayen är spärrad just nu.", tr_TR="MMI ön yolcu ekranı şu anda kilitlidir.", uk_UA="Дисплей переднього пасажира MMI наразі заблоковано.")
