texttool_globals_toast___other_screen_toast_cid = TextObject(bs_BA="%1 je zatvoren i trenutno aktivan u MMI.", cs_CZ="%1 je zavřený a aktuálně aktivní v MMI.", da_DK="%1 lukket og p.t. aktiv i MMI.", de_DE="%1 ist geschlossen und aktuell im MMI aktiv.", el_GR="Ο/Η/Το %1 είναι κλειστός/-ή/-ό και αυτή τη\nστιγμή ενεργός/-ή/-ό στο MMI.", en_GB="%1 is closed and is currently active on the\nMMI.", es_ES="La aplicación %1 está cerrada y activa en el\nMMI actualmente.", fi_FI="%1 on suljettu ja tällä hetkellä aktiivisena\nMMI:ssä.", fr_FR="L'application %1 est fermée et est\nactuellement utilisée dans le MMI.", hr_HR="Aplikacija %1 je zatvorena i trenutačno\naktivna u MMI-ju.", hu_HU="%1 bezárva, és jelenleg aktív az MMI-ben.", it_IT="L'app %1 è chiusa e al momento è attiva\nnell'MMI.", nl_NL="%1 is gesloten en momenteel actief in MMI.", no_NO="%1 er lukket og brukes nå i MMI.", pl_PL="%1 zamknięta i aktualnie aktywna w MMI.", pt_PT="%1 está fechada e atualmente ativa no MMI.", ro_RO="%1 este închisă şi momentan activă pe MMI.", ru_RU="%1 закрыто и в данный момент активно в\nMMI.", sk_SK="%1 je zatvorená a momentálne aktívna v MMI.", sl_SI="Aplikacija %1 je zaprta in trenutno aktivna v\nsistemu MMI.", sr_RS="%1 je zatvoren i trenutno aktivan u MMI.", sv_SE="%1 är stängd och aktiv i MMI.", tr_TR="%1 kapalı ve şu anda MMI'da aktif.", uk_UA="%1 закрита і зараз активна в MMI.")
texttool_globals_toast___other_screen_toast_pid = TextObject(bs_BA="%1 je zatvoren i trenutno aktivan na MMI\ndispleju suvozača.", cs_CZ="%1 je zavřený a aktuálně aktivní na displeji\nMMI spolujezdce.", da_DK="%1 lukket og p.t. aktiv i MMI-display til\nforsædepassager.", de_DE="%1 ist geschlossen und aktuell im MMI\nBeifahrerdisplay aktiv.", el_GR="Ο/Η/Το %1 είναι κλειστός/-ή/-ό και αυτή τη\nστιγμή ενεργός/-ή/-ό στην οθόνη συνοδηγού του MMI.", en_GB="%1 is closed and is currently active on the\nMMI front passenger display.", es_ES="La aplicación %1 está cerrada y activa en la\npantalla del MMI del acompañante actualmente.", fi_FI="%1 on suljettu ja tällä hetkellä aktiivisena\nMMI:n etumatkustajan näytössä.", fr_FR="L'application %1 est fermée et est\nactuellement utilisée sur l'écran MMI du passager avant.", hr_HR="Aplikacija %1 je zatvorena i trenutačno\naktivna na suvozačevom zaslonu MMI-ja.", hu_HU="%1 bezárva, és jelenleg aktív az MMI\nutaskijelzőn.", it_IT="L'app %1 è chiusa e al momento è attiva\nnell'MMI del display passeggero anteriore.", nl_NL="%1 is gesloten en momenteel in het\nMMI-bijrijdersdisplay actief.", no_NO="%1 er lukket og brukes nå på\nMMI-passasjerdisplayet.", pl_PL="%1 jest zamknięta i aktualnie aktywna na\nekranie pasażera w MMI.", pt_PT="%1 está fechada e atualmente está ativa no\necrã do passageiro do MMI.", ro_RO="%1 este închisă şi momentan activă pe\nafişajul MMI pasager faţă.", ru_RU="%1 закрыто и в данный момент активно на\nдисплее MMI переднего пассажира.", sk_SK="%1 je zatvorená a momentálne aktívna v MMI\nna displeji spolujazdca.", sl_SI="Aplikacija %1 je zaprta in trenutno aktivna na\nsovoznikovem zaslonu sistema MMI.", sr_RS="%1 je zatvoren i trenutno je u MMI displej\nsuvozača aktivan.", sv_SE="%1 är stängd och aktiv på\nMMI-passagerardisplayen.", tr_TR="%1 kapalı ve şu anda MMI ön yolcu ekranında\naktif.", uk_UA="%1 закрита і зараз активна на дисплеї MMI\nпереднього пасажира.")
